#!/bin/bashlog() {  timestamp=$(date "+%Y-%m-%d %H:%M:%S")  echo "[${timestamp}] $1"}pull_code() {  log "开始从 GitHub 拉取最新代码..."  git pull  if [ $? -ne 0 ]; then    log "拉取代码失败，请检查错误。"    exit 1  fi  log "代码拉取成功。"}build_jar() {  log "开始使用 Maven 构建 JAR 文件..."  mvn clean package -DskipTests  if [ $? -ne 0 ]; then    log "Maven 构建失败，请检查错误。"    exit 1  fi  log "JAR 文件构建成功。"}run_jave() {  log "启动java前首先删除之前的进程"}# ---------------------- 主流程 ----------------------pull_codebuild_jarrun_javelog "自动化部署流程完成！"exit 0